import glob
import os

import pytest
import yaml

import graph
from astar import a_star


FIXTURE_DIR = os.path.join(os.path.dirname(__file__), 'fixtures')


def _fixture_files():
    return sorted(glob.glob(os.path.join(FIXTURE_DIR, '*.yaml')))


def _build(spec):
    '''
    Build the (G, w) pair a_star expects from a fixture spec, reusing the
    library's own create_graph helper.
    '''
    edges = [tuple(edge) for edge in spec['edges']]
    return graph.create_graph(edges, is_directed=spec.get('directed', False))


def _make_heuristic(spec):
    '''
    Turn the fixture's node -> estimate mapping into a callable, defaulting
    to 0 (an admissible estimate) for any unlisted node.
    '''
    estimates = spec.get('heuristic', {})
    return lambda node: estimates.get(node, 0)


@pytest.fixture(params=_fixture_files(), ids=lambda path: os.path.basename(path))
def case(request):
    with open(request.param) as handle:
        return yaml.safe_load(handle)


def test_a_star_finds_expected_path(case):
    g_and_w = _build(case)
    heuristic = _make_heuristic(case)

    path, length = a_star(g_and_w, case['start'], case['goal'], heuristic)

    assert path == case['expected_path']
    assert length == case['expected_length']

